mapper.select:
SELECT COUNT(*)
FROM V_ITEMHISTORY V
WHERE V.BARCODE = #{barcode}
  AND V.USEYN = 'Y'
  AND V.KIND NOT IN('STOCKCOUNT BARCODE', 'STOCKCOUNT LOCATION', 'LOCATION')
  AND TO_TIMESTAMP(TRIM(V.MKTIME), 'YYYY-MM-DD HH24:MI:SS') > (
    SELECT MAX(TO_TIMESTAMP(TRIM(MKTIME), 'YYYY-MM-DD HH24:MI:SS'))
      FROM V_ITEMHISTORY 
     WHERE BARCODE = #{barcode}
       AND KIND = #{kind}
  )
